class OAuth2Client {
  constructor(config) {
    this.clientId = config.clientId;
    this.clientSecret = config.clientSecret;
    this.redirectUri = config.redirectUri;
    this.authorizationEndpoint = config.authorizationEndpoint;
    this.tokenEndpoint = config.tokenEndpoint;
    this.scopes = config.scopes || ['openid', 'profile', 'email'];
    this.state = this.generateState();
  }

  generateState() {
    return btoa(Math.random().toString(36).substring(2, 15) + Math.random().toString(36).substring(2, 15));
  }

  async authorize() {
    const authUrl = new URL(this.authorizationEndpoint);
    authUrl.searchParams.append('response_type', 'code');
    authUrl.searchParams.append('client_id', this.clientId);
    authUrl.searchParams.append('redirect_uri', this.redirectUri);
    authUrl.searchParams.append('scope', this.scopes.join(' '));
    authUrl.searchParams.append('state', this.state);

    window.location.href = authUrl.toString();
  }

  async handleCallback() {
    const urlParams = new URLSearchParams(window.location.search);
    const code = urlParams.get('code');
    const receivedState = urlParams.get('state');

    if (!code || receivedState !== this.state) {
      throw new Error('Invalid authorization code or state parameter');
    }

    try {
      const tokenResponse = await this.exchangeCodeForToken(code);
      this.storeTokens(tokenResponse);
      return tokenResponse;
    } catch (error) {
      console.error('Token exchange failed:', error);
      throw error;
    }
  }

  async exchangeCodeForToken(code) {
    const response = await fetch(this.tokenEndpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/x-www-form-urlencoded',
        'Authorization': 'Basic ' + btoa(`${this.clientId}:${this.clientSecret}`)
      },
      body: new URLSearchParams({
        grant_type: 'authorization_code',
        code: code,
        redirect_uri: this.redirectUri
      })
    });

    if (!response.ok) {
      throw new Error(`Token exchange failed: ${response.status}`);
    }

    return await response.json();
  }

  storeTokens(tokens) {
    const tokenData = {
      accessToken: tokens.access_token,
      refreshToken: tokens.refresh_token,
      expiresIn: tokens.expires_in,
      tokenType: tokens.token_type,
      expiresAt: Date.now() + (tokens.expires_in * 1000)
    };

    localStorage.setItem('oauth_tokens', JSON.stringify(tokenData));
  }

  getAccessToken() {
    const tokenData = localStorage.getItem('oauth_tokens');
    if (!tokenData) return null;

    const tokens = JSON.parse(tokenData);
    if (Date.now() >= tokens.expiresAt) {
      this.refreshAccessToken();
      return null;
    }

    return tokens.accessToken;
  }

  async refreshAccessToken() {
    const tokenData = localStorage.getItem('oauth_tokens');
    if (!tokenData) return null;

    const tokens = JSON.parse(tokenData);
    if (!tokens.refreshToken) return null;

    try {
      const response = await fetch(this.tokenEndpoint, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
          'Authorization': 'Basic ' + btoa(`${this.clientId}:${this.clientSecret}`)
        },
        body: new URLSearchParams({
          grant_type: 'refresh_token',
          refresh_token: tokens.refreshToken
        })
      });

      if (!response.ok) {
        throw new Error(`Token refresh failed: ${response.status}`);
      }

      const newTokens = await response.json();
      this.storeTokens(newTokens);
      return newTokens.access_token;
    } catch (error) {
      console.error('Token refresh failed:', error);
      localStorage.removeItem('oauth_tokens');
      throw error;
    }
  }

  async makeAuthenticatedRequest(url, options = {}) {
    const accessToken = this.getAccessToken();
    if (!accessToken) {
      throw new Error('No access token available');
    }

    const defaultOptions = {
      headers: {
        'Authorization': `Bearer ${accessToken}`,
        'Content-Type': 'application/json'
      }
    };

    const finalOptions = { ...defaultOptions, ...options };
    return fetch(url, finalOptions);
  }

  logout() {
    localStorage.removeItem('oauth_tokens');
    window.location.href = this.redirectUri;
  }
}

// Initialize OAuth client
const oauthClient = new OAuth2Client({
  clientId: process.env.REACT_APP_OAUTH_CLIENT_ID,
  clientSecret: process.env.REACT_APP_OAUTH_CLIENT_SECRET,
  redirectUri: process.env.REACT_APP_OAUTH_REDIRECT_URI,
  authorizationEndpoint: process.env.REACT_APP_OAUTH_AUTHORIZATION_ENDPOINT,
  tokenEndpoint: process.env.REACT_APP_OAUTH_TOKEN_ENDPOINT,
  scopes: ['openid', 'profile', 'email']
});

// Handle callback on page load
if (window.location.search.includes('code=')) {
  oauthClient.handleCallback().catch(error => {
    console.error('Authentication failed:', error);
    // Redirect to login or show error
    window.location.href = '/login';
  });
}

export default oauthClient;